#include <vector>
#include <algorithm>

std::vector<long long> solve(std::vector<long long> nums) {
    int n = nums.size();
    int two_n = 2 * n;
    std::vector<long long> ans(two_n);

    // Copy nums to the first n elements
    for (int i = 0; i < n; ++i) {
        ans[i] = nums[i];
    }

    // Copy the reverse of nums to the last n elements
    // ans[i + n] = nums[n - i - 1] for 0 <= i <= n - 1
    for (int i = 0; i < n; ++i) {
        // Index in the second half: i + n
        // Index in the original nums (reversed): n - 1 - i
        ans[i + n] = nums[n - 1 - i];
    }

    return ans;
}

